const message = $json.messages?.[0] ?? {};
const contact = $json.contacts?.[0] ?? {};
const phoneNumberId = $json.metadata?.phone_number_id;
const contactWaId = message.from;
if (!phoneNumberId || !contactWaId) {
  throw new Error('Payload sem metadata.phone_number_id ou messages[0].from');
}
const timestampRaw = Number(message.timestamp ?? Math.floor(Date.now() / 1000));
const messageTimestampMs = Number.isFinite(timestampRaw)
  ? Math.floor(timestampRaw > 10_000_000_000 ? timestampRaw : timestampRaw * 1000)
  : Date.now();
const messageType = message.type ?? 'text';
const body = message.text?.body ?? message.button?.text ?? message.interactive?.button_reply?.title ?? '';
const attachments = [];
for (const mediaType of ['image', 'document', 'audio', 'video', 'sticker']) {
  const media = message[mediaType];
  if (!media?.id) continue;
  attachments.push({
    mediaType,
    mediaId: media.id,
    contentType: media.mime_type,
    fileName: media.filename
  });
}
return [{
  json: {
    phoneNumberId,
    contactWaId,
    contactDisplayName: contact.profile?.name,
    externalMessageId: message.id,
    messageType,
    body,
    messageTimestampMs,
    attachments
  }
}];

const normalizeItems = $items('Normalize Inbound', 0, 0);
const inbound = normalizeItems?.[0]?.json ?? {};
const inboundText = typeof inbound.body === 'string' && inbound.body.trim().length > 0
  ? inbound.body.trim()
  : '[mensagem sem texto]';
const preferredMode = String($vars.AI_MODE ?? 'mock').trim().toLowerCase();
const hasOpenAiKey = typeof $vars.OPENAI_API_KEY === 'string' && $vars.OPENAI_API_KEY.trim().length > 0;
const wantsLive = preferredMode === 'live' && hasOpenAiKey;

let aiMode = 'mock';
let replyText = '';

if (wantsLive) {
  try {
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${$vars.OPENAI_API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: $vars.OPENAI_MODEL || 'gpt-4.1-mini',
        temperature: 0.3,
        messages: [
          {
            role: 'system',
            content: 'Voce e um assistente de WhatsApp para triagem inicial. Responda em portugues do Brasil, em no maximo 3 frases, pedindo proximo dado objetivo quando faltar contexto.'
          },
          {
            role: 'user',
            content: inboundText
          }
        ]
      })
    });

    if (response.ok) {
      const data = await response.json();
      const liveReply = data?.choices?.[0]?.message?.content;
      if (typeof liveReply === 'string' && liveReply.trim().length > 0) {
        aiMode = 'live';
        replyText = liveReply.trim();
      }
    }
  } catch (error) {
    // fallback para mock quando live falhar
  }
}

if (!replyText) {
  const compact = inboundText.replace(/\s+/g, ' ').trim().slice(0, 80);
  replyText = `Recebi: "${compact}". Para continuar a triagem, informe seu nome completo e a data de inicio do problema previdenciario.`;
}

return [{
  json: {
    choices: [
      {
        message: {
          content: replyText
        }
      }
    ],
    aiMode,
    model: aiMode === 'live' ? ($vars.OPENAI_MODEL || 'gpt-4.1-mini') : 'mock-deterministic-v1'
  }
}];
